// Minimum viable schema for a retro action registry entry.
// Implement in a spreadsheet, Notion database, or issue tracker.

interface RetroActionItem {
  id: string;                // unique identifier, e.g. 'RA-2024-001'
  retro_date: string;        // ISO date of the retrospective
  sprint_id: string;         // sprint where it was identified
  title: string;             // one-sentence description of the action
  completion_criterion: string; // verifiable condition for Done
  owner: string;             // single named person (no group ownership)
  due_date: string;          // ISO date — must be within two sprint cycles
  status: 'identified' | 'assigned' | 'in_sprint' | 'verified' | 'closed';
  sprint_ticket_url?: string; // link to Jira/Linear ticket
  outcome_note?: string;     // filled in when Closed — what actually happened
  closed_date?: string;      // ISO date
  is_safety_related: boolean; // safety items get mandatory review before close
}

// Example entry
const example: RetroActionItem = {
  id: 'RA-2024-047',
  retro_date: '2024-11-01',
  sprint_id: 'sprint-22',
  title: 'Lower tool-failure alert threshold from 15% to 5%',
  completion_criterion: 'PagerDuty rule updated, fires correctly on a 5% test injection',
  owner: 'morgan.lee',
  due_date: '2024-11-15',
  status: 'in_sprint',
  sprint_ticket_url: 'https://linear.app/acme/issue/ENG-1234',
  is_safety_related: true,
};
